import{c as r}from"./chunks/index.DwX68Csu.js";import{I as i,o,c as t,ak as s,J as d,k as n}from"./chunks/framework.Dpc0wyhY.js";const f=JSON.parse('{"title":"Media","description":"","frontmatter":{},"headers":[],"relativePath":"grindr-api/media/index.md","filePath":"grindr-api/media/index.md"}'),c={name:"grindr-api/media/index.md"},g=Object.assign(c,{setup(p){return(h,e)=>{const a=i("Subpages");return o(),t("div",null,[e[0]||(e[0]=s('<h1 id="media" tabindex="-1">Media <a class="header-anchor" href="#media" aria-label="Permalink to “Media”">​</a></h1><p>Media files in Grindr are stored on cdns.grindr.com:443 hosted by Amazon CloudFront powered by AmazonS3. All CDN files are accessible without <a href="/grindr-api/api-authorization">authorization</a> but some are protected with signed URLs. No <a href="/grindr-api/security-headers">security headers</a> or <code>Authorization</code> need to be present in reuqest to CDN.</p><p>Caching is supported via <a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Headers/ETag" target="_blank" rel="noreferrer">ETag header</a> — MD5 hash of image file. Image files might have <code>image/jpeg</code>, <code>image/png</code> or <code>image/webp</code> type, based on original.</p><p>Media files are identified by either a 40-character (public files) or 64-character (signed files) hexademical string. Although not confirmed for all types of media, it appears to be SHA-1 hash for 40-character hash and SHA-256 hash for 64-character hash. Confirmed cases: <a href="/grindr-api/messaging/messages#audio">Audio</a> uses SHA-256 for its 64-character mediaHash.</p><p>There are two types of files stored on CDN.</p>',5)),d(a,{items:n(r)},null,8,["items"])])}}});export{f as __pageData,g as default};
